var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 후우…….","JPN":" ふう……","ENG":"*Sigh...*","TWN":"呼呼……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 일단 급한 대로 따라오긴 했는데, 이 객차는 침식체들로부터 안전한 건가요?","JPN":" とりあえず付いてはきましたけど、この客車に侵食体のやつらが来ないとでも言うんですか？","ENG":"I had no choice but to follow you, but is this car safe from the C.O.s?","TWN":"剛才是因為情況緊急，我才跟你過來的。不過這節車廂沒問題吧？侵蝕體不會追過來嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" 안심하라. 저들은 주어진 자리를 벗어나지 않는다.","JPN":" 安心しろ。あやつらは自らに与えられた位置からは動かぬ。","ENG":"Rest easy. They do not cross the boundaries of their given position.","TWN":"放心，他們不會離開自己的區域。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" 이는 짐승이 다른 짐승의 영역을 드나들지 않음과 같은 이치일지니.","JPN":" 獣が他の獣の縄張りに侵入しないのと同じ理である。","ENG":"It is no different than that of a beast not encroaching on another's territory.","TWN":"就像動物不會擅闖其他動物的地盤一樣。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 말투가…… 좀 특이하시네요.","JPN":" 少し……変わった話し方ですね。","ENG":"Your way of speech is rather... peculiar.","TWN":"你說話的方式……有點奇妙。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그래도 도와 줘서 고마워요. 저것들에게 붙잡혔으면 큰일났을 거예요.","JPN":" でも助けてくれてありがとうございます。あいつらに捕まっていたら大変なことになっていました。","ENG":"Still, thank you for helping. It wouldn't have ended well if they caught me.","TWN":"不過還是謝謝你的幫忙，要是落入他們手裡後果可能不堪設想。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 저는 레아 슈나이더입니다. 성함이 어떻게 되시죠?","JPN":" 私はレア・シュナイダーといいます。お名前を伺っても？","ENG":"I'm Leah Schneider. What's your name?","TWN":"我叫蕾亞·修奈德，你怎麼稱呼？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" 내 너에게 <color=#ffd34c>위대한 정적</color>이라고 부를 것을 허락하겠노라.","JPN":" そなたに我を<color=#ffd34c>偉大なる静寂</color>と呼ぶことを許そう。","ENG":"I grant you permission to call me the <color=#ffd34c>Great Silence</color>.","TWN":"我允許你可以稱呼我為<color=#ffd34c>偉大的寂靜</color>。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 으음, 친해지기 어려운 이름이네요.","JPN":" う～ん、親しみやすいとは言えない名前ですね。","ENG":"Hmm, not the friendliest name.","TWN":"嗯，聽起來是很難親近的名字。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" 불경하구나. 신성한 이름을 가벼이 여기지 마라.","JPN":" 不敬な。神聖なる名を軽んじるでない。","ENG":"Blasphemous. It is a holy name that carries more weight than you could imagine.","TWN":"大膽，不准你褻瀆如此神聖的名字。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 죄송하게 됐네요. 저희 집안이 무교라서. ","JPN":" それは失礼。宗教とは無縁に育ったものですから。 ","ENG":"Well, sorry. I'm from an atheist household.","TWN":"抱歉抱歉，因為我家沒有信教。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그럼 다른 선택지는 없나요?","JPN":" 他に選択肢はないんですか？","ENG":"Are there any other names I can call you?","TWN":"那還有其他的選項嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 무지를 탓할 수는 없는 노릇. 에클레시아라고 부르는 것을 허락하노라.","JPN":" 無知を罪と責めることはできん。エクレシアと呼ぶことを許そう。","ENG":"I cannot fault one's ignorance. I grant you permission to address me as Ecclesia.","TWN":"那不能怪你無知，就允許你稱呼我為艾可露西亞吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 훨씬 낫네요.","JPN":" その方がずっとマシですね。","ENG":"Much better.","TWN":"好多咧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 좋아요, 에클레시아. 저는 침식체들이 들끓는 열차에서 더 오래 머물고 싶지 않아요.","JPN":" それでは、エクレシア。私は侵食体がうじゃうじゃといるような列車に、これ以上いたくありません。","ENG":"Okay, Ecclesia. I'm not keen on staying any longer on this C.O.-infested train.","TWN":"好的，艾可露西亞，我可不想在擠滿侵蝕體的車廂裡久留，"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 혹시 이 열차에서 내릴 방법이 있을까요?","JPN":" この列車から降りる方法はありますか？","ENG":"Is there a way to get off it?","TWN":"你知道有什麼方法可以下車嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 아니. 이 열차는 승객을 태운 뒤로 한 번도 멈추지 않고 같은 철로를 계속 달려왔다.","JPN":" ないな。この列車は乗客を乗せてからというもの、一度も止まることなく同じ線路を走り続けている。","ENG":"There is not. This train has never halted after its passengers boarded.","TWN":"沒有，一旦有乘客搭上這台列車，它就會在同樣的鐵道上持續奔馳，不會停止。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 한 번 열차에 탄 자가 어디선가 내렸다는 이야기는 들려온 적 없느니라.","JPN":" 一度列車に乗った者が、途中で降りたという話は聞いたことがない。","ENG":"There was never word of any passenger disembarking from this train.","TWN":"我從未聽說過有人在哪裡下車。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그럼 중간역이나 종착지는요?","JPN":" では途中駅とか、終着駅は？","ENG":"What about any train stations or the train terminal?","TWN":"那中間停靠站跟終點站呢？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 없다. 내가 아는 한에는.","JPN":" ない。少なくとも我の知る限りでは。","ENG":"No one. At least, to my knowledge.","TWN":"據我所知，沒有。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 아, 그래요. 참 가성비 좋은 열차 여행이네요.","JPN":" なるほど。列車の旅としてはコスパ最強ですね。","ENG":"Ah, is that so. What a cost-efficient trip.","TWN":"是喔，那這趟列車之旅的CP值還真高。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 어디 볼까, 차량번호대로라면 여기가 끝에서 두 번째 칸인데…….","JPN":" えっと、車両番号通りなら、ここが後ろから2番目の車両だから……","ENG":"Let's see, the car number indicates that this is the second-to-last passenger car...","TWN":"我看看喔，按照這台列車編號，這裡是倒數第二節車廂……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 에클레시아, 기관실까지 안내해 줄 수 있나요?","JPN":" エクレシア、機関室まで案内してもらえませんか？","ENG":"Ecclesia, can you lead me to the engine room?","TWN":" 艾可露西亞，可以帶我到駕駛室嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 기관실?","JPN":" 機関室？","ENG":"The engine room?","TWN":"駕駛室？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 네. 기관실을 점거해서 열차를 세우려고요.","JPN":" はい。機関室を占拠して、列車を止めてみようと思います。","ENG":"Yes. I'm going to take over the engine room and stop the train.","TWN":"對，我想直接從駕駛室強制讓列車停下。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 침식체로 가득찬 객차를 가로질러 가는 것도 쉽진 않겠지만….","JPN":" 侵食体でいっぱいの客車を通っていくのは簡単ではありませんが……","ENG":"It won't be easy to run across a passenger car full of C.O.s, but...","TWN":"雖然要穿過擠滿侵蝕體的車廂也不容易…"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 달리는 열차에서 맨몸으로 뛰어내리는 것보다는 성공할 확률이 높겠죠.","JPN":" 走行中の列車から飛び降りるよりは成功率が高そうですから。","ENG":"I'll have a better chance of making it out alive than jumping off a moving train.","TWN":"但存活率應該比直接從奔馳的列車中往下跳來得高吧？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 그렇게까지 해서라도 열차에서 내려야 할 이유가 있는 것인가?","JPN":" そこまでして列車から降りなければいけない理由があるのか？","ENG":"What is it that you are attempting to achieve by disembarking the train?","TWN":"為什麼非下車不可？有什麼理由嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 아직 못 다한 일이 있어서요.","JPN":" まだやり終えていない仕事があるんです。","ENG":"I just have some unfinished business.","TWN":"因為我還有未完成的事。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 이것만으로는 이유로 부족할까요?","JPN":" この理由では足りませんか？","ENG":"Is that a good enough reason?","TWN":"這樣還不足以成為非下車不可的理由嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" ……아니. 충분하다. 너의 뜻이 정녕 그러하다면.","JPN":" ……いや、十分だ。そなたがそこまで言うのであれば。","ENG":"...Yes, I suppose it is. If that is your will.","TWN":"……可以，若你執意如此。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 기관실까지 안내해 주마. 가자.","JPN":" 機関室まで案内しよう。付いてこい。","ENG":"I shall guide you to the engine room. Follow me.","TWN":"那我帶你去駕駛室，走吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 속내도 모르겠고, 어디서 나타났는지도 모르겠지만…….","JPN":" 考えも読めないし、どこから現れたのかもわからないけれど……","ENG":"I don't know her intentions or where she came from, but...","TWN":"雖然不清楚她的來歷和背景……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 지금 믿을 수 있는 건 이 사람뿐이야.","JPN":" 今頼れるのはこの人しかいない。","ENG":"She's the only one I can trust right now.","TWN":"但我現在能夠相信的人就只有她了。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그래. 지금은.","JPN":" そうだ。今は。","ENG":"For now, at least.","TWN":"沒錯，目前而言。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 고마워요. 잘 부탁해요, 에클레시아.","JPN":" ありがとうございます。よろしくお願いします、エクレシア。","ENG":"Thanks, Ecclesia.","TWN":"謝謝，那就麻煩你了，艾可露西亞。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};